update cotdl.tbl_piiorder
   set 
		confirmflag= #{confirmflag, jdbcType=VARCHAR},
		holdflag= #{holdflag, jdbcType=VARCHAR},
		forceokflag= #{forceokflag, jdbcType=VARCHAR}
		
where orderid= #{orderid}

update cotdl.tbl_piiorder
   set 
		status= #{status, jdbcType=VARCHAR}
where orderid= #{orderid}

mapper.select:
 
		 
		select 
			orderid, basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, runningtime, realstarttime, realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, orderdate, orderuserid

		from ( 
				select 
					 ROWNUM rn, orderid, basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, runningtime, realstarttime, realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, orderdate, orderuserid
				from (
						select orderid, to_char(basedate,'yyyy/mm/dd') as basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, to_char(eststarttime,'yyyy/mm/dd hh24:mi:ss') as eststarttime, runningtime, to_char(realstarttime,'yyyy/mm/dd hh24:mi:ss') as realstarttime, to_char(realendtime,'yyyy/mm/dd hh24:mi:ss') as realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, to_char(orderdate,'yyyy/mm/dd hh24:mi:ss') as orderdate, orderuserid
					  	  from cotdl.tbl_piiorder  
					  	  		

		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and trunc(basedate) = (to_date(#{search2, jdbcType=VARCHAR},'yyyymmdd'))
						
						
							and orderuserid = #{search3}
						
						
							and status = #{search4}
						
						
							and runtype = #{search5}
						
		
	    
	    
					  	  order by orderid desc
					 ) f
				 

				
				order by orderid desc
			  ) d
		where rn <= #{pagenum} * #{amount} 
		  and rn > (#{pagenum} -1) * #{amount} 
		order by orderid desc

select orderid, basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, runningtime, realstarttime, realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, orderdate, orderuserid , (select LISTAGG(orderid, ',') WITHIN GROUP(ORDER BY orderid) from cotdl.tbl_piiorder where jobid=d.jobid and status in ('Ended not OK', 'Running', 'Hold') and orderid!=d.orderid) as waitreason_samejobnotcompleted , (case when eststarttime_org > SYSDATE then eststarttime else '' end) as waitreason_executiontime , (case when (select count(distinct jobid_w) from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') != (select count(1) from cotdl.tbl_piiorder c where c.jobid in (select jobid_w from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') and c.basedate = d.basedate and c.status = 'Ended OK' ) then (select LISTAGG(jobid, ',') WITHIN GROUP(ORDER BY jobid) from (select distinct jobid_w as jobid from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE' minus select distinct c.jobid as jobid from cotdl.tbl_piiorder c where c.jobid in (select jobid_w from cotdl.tbl_piiorderjobwait b where d.orderid = b.orderid and type='PRE') and c.basedate = d.basedate and c.status = 'Ended OK' )) else null end) as waitreason_waitjob from ( select ROWNUM rn, orderid, basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, eststarttime, eststarttime_org, runningtime, realstarttime, realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, orderdate, orderuserid from ( select orderid, to_char(basedate,'yyyy/mm/dd') as basedate, runcnt, jobid, version, jobname,system, policy_id, keymap_id, jobtype, runtype, calendar, time, status, confirmflag, holdflag, forceokflag, killflag, to_char(eststarttime,'yyyy/mm/dd hh24:mi:ss') as eststarttime, eststarttime as eststarttime_org, runningtime, to_char(realstarttime,'yyyy/mm/dd hh24:mi:ss') as realstarttime, to_char(realendtime,'yyyy/mm/dd hh24:mi:ss') as realendtime, job_owner_id1, job_owner_name1, job_owner_id2, job_owner_name2, job_owner_id3, job_owner_name3, to_char(orderdate,'yyyy/mm/dd hh24:mi:ss') as orderdate, orderuserid from cotdl.tbl_piiorder
and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
and trunc(basedate) = (to_date(#{search2, jdbcType=VARCHAR},'yyyymmdd'))
and orderuserid = #{search3}
and status = #{search4}
and runtype = #{search5}
order by orderid desc ) f
order by orderid desc ) d where rn <= #{pagenum} * #{amount} and rn > (#{pagenum} -1) * #{amount} order by orderid desc

